import React, { useEffect, useState } from 'react';
import { GoogleMap, LoadScript, TrafficLayer } from '@react-google-maps/api';
import api from '../services/api';
import mapStyles from '../components/mapStyles';

const containerStyle = {
  width: '100%',
  height: '600px',
};

const center = {
  lat: 37.7749,
  lng: -122.4194,
};

const TrafficLayerPage = () => {
  const [showTraffic, setShowTraffic] = useState(true);
  const [vehicleStats, setVehicleStats] = useState({ active: 0, idle: 0, maintenance: 0 });
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    const fetchVehicleStats = async () => {
      try {
        const response = await api.get('/vehicles');
        const vehicles = response.data;
        setVehicleStats({
          active: vehicles.filter(v => v.status === 'ACTIVE').length,
          idle: vehicles.filter(v => v.status === 'IDLE').length,
          maintenance: vehicles.filter(v => v.status === 'MAINTENANCE').length,
        });
        setLoading(false);
      } catch (err) {
        console.error('Error fetching vehicle stats:', err);
        setLoading(false);
      }
    };

    fetchVehicleStats();
  }, []);

  return (
    <div className="space-y-6">
      <h2 className="g-title">Traffic Layer</h2>
      <div className="flex space-x-4 mb-4">
        <button
          className="g-btn"
          onClick={() => setShowTraffic(!showTraffic)}
        >
          {showTraffic ? 'Hide Traffic' : 'Show Traffic'}
        </button>
      </div>
      <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">
        <div className="lg:col-span-2 stat-card">
          <h3 className="text-lg font-semibold mb-4">Traffic Map</h3>
          {loading ? (
            <p className="text-gray-600">Loading map...</p>
          ) : (
            <LoadScript googleMapsApiKey="AIzaSyCKgddaxzo_Fu2edk6qyN4g4qqEAvFcAaY">
              <GoogleMap
                mapContainerStyle={containerStyle}
                center={center}
                zoom={10}
                options={{ styles: mapStyles }}
              >
                {showTraffic && <TrafficLayer autoRefresh />}
              </GoogleMap>
            </LoadScript>
          )}
        </div>
        <div className="stat-card">
          <h3 className="text-lg font-semibold mb-4">Vehicle Status Summary</h3>
          {loading ? (
            <p className="text-gray-600">Loading stats...</p>
          ) : (
            <div className="space-y-2">
              <p className="bg-blue-100 p-2 rounded">Active: {vehicleStats.active}</p>
              <p className="bg-yellow-100 p-2 rounded">Idle: {vehicleStats.idle}</p>
              <p className="bg-red-100 p-2 rounded">Maintenance: {vehicleStats.maintenance}</p>
            </div>
          )}
        </div>
      </div>
    </div>
  );
};

export default TrafficLayerPage;
